using namespace RTB;

// ============================================================
// Helpers
// ============================================================

static constexpr double kTight = 1e-9;   // tight double tolerance
static constexpr double kLoose = 1e-4;   // loose tolerance for approximations
static constexpr double kMed   = 1e-6;   // medium tolerance

/** True if a point lies on the ellipsoid surface (within tol). */
static bool OnSurface(const Point<double, 3>& p, double A, double B, double C,
                      double tol = 1e-6) {
    double val = (p[0] * p[0]) / (A * A) + (p[1] * p[1]) / (B * B) +
                 (p[2] * p[2]) / (C * C);
    return std::abs(val - 1.0) < tol;
}

